interface.definition:
a!localVariables(
  local!step: 1,

  if(
    local!step = 1,
    #"SYSTEM_SYSRULES_formLayout_v1"(
      label: "Druck Kontoinformation",
      contents:
        #"SYSTEM_SYSRULES_columnsLayout"(
          alignVertical: "MIDDLE",
          columns: {
            #"SYSTEM_SYSRULES_columnLayout"(
              width: "2X"
            ),
            #"SYSTEM_SYSRULES_columnLayout"(
              width: "10X",
              contents: {
                #"SYSTEM_SYSRULES_cardLayout"(
                  contents: {},
                  height: "SHORT_PLUS",
                  showBorder: false
                ),
                #"SYSTEM_SYSRULES_cardLayout"(
                  contents: {
                    #"SYSTEM_SYSRULES_richTextDisplayField"(
                      align: "CENTER",
                      value: {
                        #"SYSTEM_SYSRULES_richTextItem_v1"(
                          text: "Möchten Sie Ihre aktuellen Kontoinformationen (Kontostände und -bewegungen/Umsätze) ausdrucken lassen?",
                          size: "MEDIUM",
                          style: "STRONG"
                        )
                      },
                      marginAbove: "STANDARD",
                    ),
                    #"SYSTEM_SYSRULES_richTextDisplayField"(
                      align: "CENTER",            
                      value: #"SYSTEM_SYSRULES_richTextItem_v1"(
                        text: "Bitte beachten Sie, dass Ihnen hierbei Kosten entstehen.",
                        size: "MEDIUM",
                        style: "EMPHASIS"
                      ),
                      marginBelow: "STANDARD",
                    ),
                  },
                  style: "INFO",
                  showBorder: false,
                  showShadow: true,
                  shape: "SEMI_ROUNDED",
                  marginBelow: "STANDARD",
                ),
                #"SYSTEM_SYSRULES_cardLayout"(
                  contents: {},
                  height: "SHORT_PLUS",
                  showBorder: false
                ),
              }
            ),
            #"SYSTEM_SYSRULES_columnLayout"(
              width: "2X"
            )
          }
        ),
        buttons: #"SYSTEM_SYSRULES_ButtonLayout"(
          primaryButtons: #"SYSTEM_SYSRULES_buttonWidget_v1"(
            label: "Bestätigen und Absenden",
            style: "SOLID",
            value: 2,
            saveInto: local!step
          ),
          secondaryButtons: #"SYSTEM_SYSRULES_buttonWidget_v1"(
            label: #"urn:appian:translation-string:v1:d940fe67-4bc0-43d9-9eca-be0aa0394b8a",
            saveInto: {},            
          )
        )        

    ),
    #"SYSTEM_SYSRULES_formLayout_v1"(
      label: "Druck Kontoauszug",
      contents:
      #"SYSTEM_SYSRULES_columnsLayout"(
        columns: {
          #"SYSTEM_SYSRULES_columnLayout"(
            width: "2X"
          ),
          #"SYSTEM_SYSRULES_columnLayout"(
            contents: {
              #"SYSTEM_SYSRULES_cardLayout"(
                contents: {},
                height: "SHORT_PLUS",
                showBorder: false
              ),
              #"SYSTEM_SYSRULES_cardLayout"(
                contents: {
                  #"SYSTEM_SYSRULES_richTextDisplayField"(
                    value: {
                      #"SYSTEM_SYSRULES_richTextItem_v1"(
                        text: "Der Druckauftrag wurde an den allgemeinen Vollzugsdienst (AVD) gesendet. " & char(10) & char(10) & "Sie können den Druck zeitnah abholen und die Gebühr entrichten.",
                        size: "MEDIUM",
                      )
                    },
                    align: "CENTER",
                    marginAbove: "STANDARD",
                    marginBelow: "STANDARD"
                  ),
                },
                style: "INFO",
                shape: "SEMI_ROUNDED",
                marginBelow: "STANDARD",
                showBorder: false,
                showShadow: true
              ),
              #"SYSTEM_SYSRULES_cardLayout"(
                contents: {},
                height: "SHORT_PLUS",
                showBorder: false
              )
            },
            width: "10X"
          ),
          #"SYSTEM_SYSRULES_columnLayout"(
            width: "2X"
          )
        },
        alignVertical: "MIDDLE"
      ),
      buttons: #"SYSTEM_SYSRULES_ButtonLayout"(
        primaryButtons: #"SYSTEM_SYSRULES_buttonWidget_v1"(
          label: "Schließen",
          saveInto: {},
          submit: true, 
          style: "SOLID"
        )
      )
    )
  )
)
